CREATE TRIGGER LG_KSLINES_INS_099_01 ON LG_099_01_KSLINES
FOR INSERT
AS
DECLARE @TRCODE    SMALLINT
DECLARE @TRDATE    DATETIME
DECLARE @TRSIGN    SMALLINT
DECLARE @CASHREF   INT
DECLARE @AMOUNT    FLOAT
DECLARE @REPORTNET FLOAT
DECLARE @TRNET FLOAT
DECLARE @TRCURR SMALLINT
DECLARE @CANCELLED SMALLINT
DECLARE @STATUS    SMALLINT
SELECT @TRCODE    = I.TRCODE,
       @TRDATE    = I.DATE_,
       @TRSIGN    = I.SIGN,
       @CASHREF   = I.CARDREF,
       @AMOUNT    = I.AMOUNT,
       @REPORTNET = I.REPORTNET,
       @TRNET = I.TRNET,
       @TRCURR = I.TRCURR,
       @CANCELLED = I.CANCELLED,
       @STATUS    = I.STATUS FROM INSERTED I
EXECUTE LG_UPDATE_CASHTRANS_099_01 1, @TRCODE, @TRDATE, @TRSIGN, @CASHREF,
                                   @AMOUNT, @REPORTNET, @TRNET, @TRCURR, @CANCELLED, @STATUS
